def _moment_cards(review_windows: list[dict[str, Any]]) -> list[dict[str, Any]]:
    cards: list[dict[str, Any]] = []
    for window in review_windows[:6]:
        metric_evidence = (
            f"overall={window['metrics']['overall_score']:.1f}, "
